INSERT OR IGNORE INTO users (id,email,username,display_username,display_name,email_verified,created_at,updated_at) VALUES ('snapback-official','official@snapbacksports.com','snapback','Snapback','Snapback',1,'2026-07-12T21:14:43.099Z','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('e5efe4650efdd4813b197576','venue','3632','getting-there','snapback-official','Snapback','Logistics are rough. Bad traffic in and out, long bathroom and food lines, and basically no phone service inside. Screenshot your tickets and set a meetup spot beforehand.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('54f981bad9056d35f589d3a0','venue','3632','getting-there','snapback-official','Snapback','State College is a haul. It is a small regional airport and you will likely connect through somewhere. Treat it as a fly-in-for-the-weekend, one-and-done trip.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('87cac2b6e66476521a1170d0','venue','3632','best-seats','snapback-official','Snapback','Tightest bleacher seating we have ever sat in. It is raw, authentic college football, but expect zero legroom and no room to spread out.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('aa3ee48df54440f876f3a5a4','venue','3632','best-seats','snapback-official','Snapback','The stadium itself is not fancy and there is no room to spare. You are here for the crowd and the spectacle, not the amenities.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('2c0faf6f292355fcae5757b9','venue','3632','food','snapback-official','Snapback','Food is the weak spot. We scored it a 4 out of 10. Skip the cheesesteak, it is dry here. Grab chicken tenders and fries and call it a day.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('761fea791474793856ee7536','venue','3632','food','snapback-official','Snapback','Treat stadium food as halftime fuel only. Tailgate all day, then grab tenders, fries, and the donut bites once you are inside.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('99aa40f17a26239a2c227d91','venue','3632','before','snapback-official','Snapback','Tailgating is the event here. Grills going all day, footballs flying everywhere. Get there early and post up before kickoff.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('28eeb18b5c32de9e51cc6207','venue','3632','before','snapback-official','Snapback','Pre-game move: hit anti-fragile, a newer brewery in town.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('2d9ede9ed4caa7a771712e80','venue','3632','before','snapback-official','Snapback','Look for a communion tailgate. Fans run a prayer and a song and toast Fireball after the first down and every touchdown. It is a Penn State tradition worth catching.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('93655cc68b17f92915188678','venue','3632','atmosphere','snapback-official','Snapback','The White Out is widely regarded as the single greatest atmosphere in college football. The whole place goes all white, plus fireworks and Mo Bamba. Walking out of the tunnel into it is genuinely breathtaking.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('7fa30b6fb052b2e3924185ed','venue','3632','atmosphere','snapback-official','Snapback','Beaver Stadium is the second biggest stadium in the country, around 107k, and it is loudest for marquee games. Fans said the pick six against Ohio State was the loudest they had ever heard it.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('42d882d2976ab638b18cc7b1','venue','3632','tips','snapback-official','Snapback','There is only one White Out a year, and it truly peaks as a night game against a top rival like Ohio State or Michigan. If you can pick your game, pick that one.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('f762aba608988a563fa4c797','venue','3632','tips','snapback-official','Snapback','Wear all white. That is the entire point. Showing up in your own team colors to a White Out misses it.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('5d9d35537cba52af65b86ec8','venue','3632','tips','snapback-official','Snapback','Pair the trip with campus. Old Main and the fall foliage in Happy Valley are gorgeous. See the White Out once, soak in State College, and call it a great weekend.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO reviews (id,scope,target_id,game_id,user_id,author,rating,body,created_at) VALUES ('snapback-review-3632','venue','3632',NULL,'snapback-official','Snapback',7,'Went up for the White Out and the atmosphere absolutely lived up to the hype. 107,000 people all in white, the lights drop, the fireworks go off and they blast Mo Bamba, and walking out of that tunnel honestly gave me chills. When the whole place is locked in it is the loudest thing I have ever been a part of.

Real talk though, the rest of it is rough. We tailgated all day and that was the best part, grills everywhere, footballs flying, people just handing you food. But inside the stadium the food is bad, just get the chicken tenders and fries and keep your expectations low. The bleachers are packed so tight you are basically sitting on the person next to you, there is no phone service, and the lines and traffic are a grind.

The honest truth is the game makes or breaks it. We caught a blowout against Washington and a big chunk of the crowd left by the third quarter, so we never got that signature White Out moment late. If you can get here for a night game against Ohio State or Michigan, that is when this place is a 10. For a regular White Out it is still worth seeing once, especially paired with a weekend in Happy Valley, but it is a long expensive trip so plan around the right opponent.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('1abd3655f0487576d861f1ae','venue','30','food','snapback-official','Snapback','The priciest item is the $30 jalapeno bacon Philly fry, served in a helmet you can actually wear. We did a full lap and it was the most expensive thing in the park, and it is genuinely good, a 7.9 out of 10.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('b970280f96ed9343d550b583','venue','1949','food','snapback-official','Snapback','The most expensive item is only a $17 chicken Philly, about a 6 out of 10. Get it early. It is best fresh in the first quarter and slides downhill sitting out.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('793d9c28ca73acebfefc067b','venue','1949','getting-there','snapback-official','Snapback','Buy your tickets ahead of time. The box office closed during the game and the ticketing apps stopped selling once it was underway.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('862e2e0412a382ffb0703218','venue','3752','food','snapback-official','Snapback','Food is rough. The nicest item from Prantl Bros, the pittsburger, came in at a 1.8 out of 10 with an untoasted bun and soggy fries. Keep expectations low.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('4350fccce81e1782fe515aae','venue','3752','food','snapback-official','Snapback','Club level food is a real upgrade. We had southwestern chicken egg rolls and a chicky pizza for $36, about a 6.9, and it was actually good. Pay up for the better seats if you can.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('11c3ec0f0c7052a1edc13d96','venue','3752','best-seats','snapback-official','Snapback','The stadium is a concrete ice pit and Renegade can feel underwhelming, but the crowd shows up for prime-time games. Even a game the media called unwatchable turned into a shootout.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('76c3c80a403fd3b3e0719619','venue','3752','atmosphere','snapback-official','Snapback','Steelers fans are brutally honest about their own team and will heckle their own side when it is going badly. It can get rowdy, but they were friendly to us as visitors.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('5a70f2e620d5ee4afbb6dd5a','venue','3752','tips','snapback-official','Snapback','There is a tradition where first-timers on the field eat a piece of the grass. The fans will absolutely make you do it.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO reviews (id,scope,target_id,game_id,user_id,author,rating,body,created_at) VALUES ('snapback-review-3752','venue','3752',NULL,'snapback-official','Snapback',4,'Pittsburgh gets a bad rap and honestly some of it is earned. The Prantl Bros pittsburger is rough, untoasted bun and soggy fries, and the stadium is a concrete ice pit where Renegade did not do much for me.

But here is the thing. When we came back and got club level seats the food was a real upgrade, and even a prime-time game the entire media said was unwatchable turned into a shootout. The fans are brutally honest about their own team but they show up. It is not bucket list, but it is better than its reputation, and watch out, the fans will make you eat a piece of the field grass.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('9fad24002c0572a0d3d4d4d1','venue','3933','getting-there','snapback-official','Snapback','Getting in is fast, often 15 to 20 minutes or less despite what the reviews say. The catch is getting out. Longtime fans say it can take close to an hour to leave after the game.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('95a45190ff9e4a85cdbe4502','venue','3933','getting-there','snapback-official','Snapback','The traffic here rivals Los Angeles. Plan extra time on both ends.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('3869402a7f058362afc2241c','venue','3933','before','snapback-official','Snapback','Parking and tailgating are a highlight. Get there early and tailgate, regulars say it is the best part of the day.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('ad1d5f8fb132665614acf82c','venue','3933','food','snapback-official','Snapback','Get the hot dog, it is a genuinely good dog. Skip the pizza, it is small, cold and not good. The concession staff were friendly and quick.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('dfeecbe9c91583a1282016fd','venue','3933','atmosphere','snapback-official','Snapback','The fans are the whole show. Loud and screaming the entire game even when the Bears are bad, and friendly with no real attitude. Easily a five star crowd.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('da7ffb1516d7fb5fa14f2dc1','venue','3933','tips','snapback-official','Snapback','Ignore the one star reviews. The grass is green, getting in is quick, and the staff are nice. The team may struggle but the experience holds up.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO reviews (id,scope,target_id,game_id,user_id,author,rating,body,created_at) VALUES ('snapback-review-3933','venue','3933',NULL,'snapback-official','Snapback',8,'Everyone warned us Soldier Field would be the worst experience in the NFL, and it was the opposite. We got in under two minutes, not the hour the reviews swore by.

The fans are unreal, loud and screaming the whole game even though the Bears are not good, and friendly the entire time, no attitude and no shoving. Get the hot dog, it is a quality dog, but skip the pizza, it is cold and tiny. The stadium is old, the food is mostly terrible and the traffic rivals LA, those are the real knocks.

Even so, this was an easy great night. The fan base is obsessive and they suck you in. On atmosphere alone you will be smiling ear to ear, and I would go back tomorrow.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('afb4b937c2e81dfa58858a15','venue','3839','before','snapback-official','Snapback','Get there early for the tailgate. There were free samples, beer flowing, and tons of throwback jerseys around the lot.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('33ef4e4eae0df02be7c15dc4','venue','3839','atmosphere','snapback-official','Snapback','Jets fans are friendly despite the New York reputation. Fireman Ed, the longtime Jets superfan, sits up in the club section, section 114.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('1890a55196ad1701bc30747f','venue','3839','best-seats','snapback-official','Snapback','Honest warning, the stadium is ugly and it gets freezing cold, and the food is beyond mid. For a bad matchup this is a skip.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO reviews (id,scope,target_id,game_id,user_id,author,rating,body,created_at) VALUES ('snapback-review-3839','venue','3839',NULL,'snapback-official','Snapback',3,'I live less than ten miles from MetLife and I will still say it, this is a wouldn''t go if you paid me experience for a bad game. The stadium is ugly, it was freezing, the food is beyond mid, and the matchup we caught was awful enough that we left early.

The tailgate does have some life, free samples and throwback jerseys everywhere, and Jets fans are friendlier than the New York reputation suggests. But unless it is a big game, there are far better trips.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('9a5d49c3cf76664e85cf70bd','venue','3687','atmosphere','snapback-official','Snapback','The stadium is a spectacle. It is a $1.3 billion complex so massive that a Statue of Liberty standing on the Dallas star at midfield would not reach the roof. There is even a car dealership inside.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('c0ccb9f7534684917ec4bd44','venue','3687','getting-there','snapback-official','Snapback','AT&T Stadium is a bit tough to navigate. Give yourself extra time to find your section.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('71836f51a477eb6359c3870c','venue','3687','food','snapback-official','Snapback','The Cowboys cheese Philly, their take on a cheesesteak, and the brisket sandwich are the moves. If you get suite access, the spread including the Cheeto-dust popcorn is insanely good.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('9f84c7be8340b255f3ba6aba','venue','3687','atmosphere','snapback-official','Snapback','Heads up, a lot of Cowboys fans are entitled and loud about glory that is 30 years old. The place still delivers on scale and big games.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('b62dcca8c8034850b42e040f','venue','3687','tips','snapback-official','Snapback','If you can, tour Jerry World on a non-game day. The locker room, Jerry Jones suite, and the views are worth it on their own and push the whole thing toward bucket list.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO reviews (id,scope,target_id,game_id,user_id,author,rating,body,created_at) VALUES ('snapback-review-3687','venue','3687',NULL,'snapback-official','Snapback',8,'AT&T Stadium is a spectacle. It is a $1.3 billion building, so huge that the Statue of Liberty on the midfield star would not touch the roof, and yes there is a car dealership inside.

We got field passes before and after the game and a full suite spread, and the Cheeto-dust popcorn was unreasonably good. We also caught the best game of the entire season here, 76 points. The fans can be a little entitled and the place is tough to navigate, but the scale is unreal. If you can swing a non-game-day tour of the locker room and Jerry''s suite, it pushes the whole thing right up against bucket list.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('e813d45fcf75cb00cd74158b','venue','3622','atmosphere','snapback-official','Snapback','This is the loudest set of fans in football. Between the chop and the chance of Mahomes magic on any play, Arrowhead stays in a frenzy all game.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('584eeef973550b2099f76fa2','venue','3622','food','snapback-official','Snapback','The food is unreal. Our top rated stadium item of the entire season was here, an ice cream dish we scored a 9 with the ice cream.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('45bf2efc606004a86fa5b697','venue','3622','tips','snapback-official','Snapback','Kansas City the city leaves something to be desired, so plan the trip around the game. If you eat anywhere, Joe''sBarbecue is the best we have ever had.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO reviews (id,scope,target_id,game_id,user_id,author,rating,body,created_at) VALUES ('snapback-review-3622','venue','3622',NULL,'snapback-official','Snapback',8,'Arrowhead is the loudest building in football, full stop. Between the chop and Mahomes being able to make magic on any snap, the place is in a frenzy the whole game.

The food is also the best we had all season, our top rated item of the year was here, an ice cream dish that is a 9. The only reason it is not bucket list for us is that Kansas City the city leaves a bit to be desired. Come for the game and hit Joe''sBarbecue, which is the best we have ever had.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('5583a9082dedfe6c8af9343b','venue','3806','atmosphere','snapback-official','Snapback','Eagles fans are the best in football as long as you are on their good side. Do not show up as an opposing fan, and do not show up if you are not bringing your best energy.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('b888a942a5841b16bd3b3dc8','venue','3806','food','snapback-official','Snapback','The stadium itself is nothing special and the food is really bad. Come for the crowd and the game, not the concessions.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('10fc691be999ec91b906f9d3','venue','3806','before','snapback-official','Snapback','Tailgate first, the cheesesteaks and Go Birds energy outside are the best part. We would not bring anyone under 21.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO reviews (id,scope,target_id,game_id,user_id,author,rating,body,created_at) VALUES ('snapback-review-3806','venue','3806',NULL,'snapback-official','Snapback',8,'Philly is an A-tier experience carried entirely by its fans, the best in football as long as you are on their good side. We hosted a tailgate with a hundred of our own fans, cheesesteaks and Go Birds everywhere, and that pregame is the highlight.

Inside, the stadium is nothing special and the food is really bad, so just lock into the game. Fair warning, it gets rowdy and we would not bring anyone under 21, but if you want raw passion this is it.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('122cfcb4ad652f52601e9c1f','venue','4738','before','snapback-official','Snapback','The Niners have the best tailgate in football, better than Buffalo. We got free tacos and tequila just for winning a trivia game in the lot.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('6399ef4af1cfe5eb89f85944','venue','4738','best-seats','snapback-official','Snapback','This is the most beautiful outdoor stadium in the NFL with great food options and an elite team. Worth the trip even if it means a long flight plus an hour drive down to Santa Clara.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('cded0b64ba1a0015fa0a0f23','venue','4738','atmosphere','snapback-official','Snapback','One honest knock, the fans can be quiet and not everyone stands, especially in a blowout. The stadium and the food carry it.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO reviews (id,scope,target_id,game_id,user_id,author,rating,body,created_at) VALUES ('snapback-review-4738','venue','4738',NULL,'snapback-official','Snapback',9,'Levi''s is a bucket-list experience and it surprised us how worth it the whole day was, even with a six hour flight and an hour drive down to Santa Clara.

The Niners have the best tailgate in football, we got free tacos and tequila just for winning some trivia in the lot. Inside it is the most beautiful outdoor stadium in the NFL, great food, elite team. The one knock is the crowd can be quiet and not everyone stands, but the place itself is special. Put it on your list.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('b85a607489d303b957b18dfc','venue','3798','before','snapback-official','Snapback','Before the game you get Titletown plus crawls and tailgates in people''s actual backyards. There is no bad experience at Lambeau.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('1d680434c371750d8a64e9c1','venue','3798','food','snapback-official','Snapback','Get the cheese curds and a Spotted Cow. We tasted them and they are genuinely delicious.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('d7351268166f429ebad8df56','venue','3798','atmosphere','snapback-official','Snapback','You can feel the history, tradition, and love for the Packers in this place. If you love football, you have to make it to Lambeau once in your lifetime.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('377fe5c58471fffb81a2c267','venue','3798','tips','snapback-official','Snapback','There is not much to do in Green Bay besides football, and honestly that is the point. Build the trip entirely around the game.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO reviews (id,scope,target_id,game_id,user_id,author,rating,body,created_at) VALUES ('snapback-review-3798','venue','3798',NULL,'snapback-official','Snapback',9,'Lambeau is the mecca of football experiences and our number one of the entire season.

Before the game you get Titletown plus crawls and tailgates in people''s actual backyards, and there is genuinely no bad experience here. Get the cheese curds and a Spotted Cow, both delicious. Inside you can feel the history and the love for the Packers in a way no other building has. There is not much to do in Green Bay besides football, which is exactly why a Packers game is bucket list. If you love football, get here once in your life.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('90f6336f9a0652977896c86a','venue','3719','food','snapback-official','Snapback','Surprisingly, the Commanders had the best stadium food of our entire NFL season. The crab egg rolls and the cheesesteak are the move.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('d45526c7eb210a657ca768e3','venue','3719','getting-there','snapback-official','Snapback','There was basically no one tailgating, so do not count on a big pregame scene here.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('24a07e09b76d41c0b8f4a833','venue','3719','tips','snapback-official','Snapback','If you get free tickets you should probably go, but it is not a destination on its own. The food is the highlight.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('c3e2c8d3ec6ab93c3bb0baf8','venue','3493','before','snapback-official','Snapback','No tailgating, but the pregame is the coolest in the league. A massive open courtyard stocked with bars and live music, plus Bourbon Street steps away.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('665d1c19aa67118767a7fdb1','venue','3493','best-seats','snapback-official','Snapback','After the renovations the Superdome is easy to navigate. If you have a few extra bucks, sit down below rather than up top, it makes a big difference.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('564b2ce0940e1f4db6c4cdcc','venue','3493','food','snapback-official','Snapback','The food is genuinely unique. Try the alligator hot dog.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('d8b4a5c77d834bceb58ddf39','venue','3493','tips','snapback-official','Snapback','Spend an extra day in New Orleans for the food and culture. A Saints game is bucket list, and a playoff game would be unreal.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO reviews (id,scope,target_id,game_id,user_id,author,rating,body,created_at) VALUES ('snapback-review-3493','venue','3493',NULL,'snapback-official','Snapback',9,'The Superdome is a bucket-list experience, our number three of the season.

There is no tailgating, which sounds strange, but the pregame is the coolest in the league, a huge open courtyard with bars and live music and Bourbon Street right there. After the renovations the building is easy to get around, the entertainment and environment are top notch, and the food is genuinely unique, get the alligator hot dog. My one tip, sit down below instead of up top if you can swing it, it makes a real difference. Spend an extra day in Nola for the food and culture and you have a perfect trip.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('a9193301f966a46150d6abb1','venue','3883','atmosphere','snapback-official','Snapback','Bills fans are die-hard and the passion is real, but our hot take is that the hammer lot tailgate is a bit overrated.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('2c1b925f8d53a9374523e7ff','venue','3883','food','snapback-official','Snapback','The food is miserable. Do not get the fries, they were a 0 out of 10.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('34838f0db56de70aa4c5adf0','venue','3883','getting-there','snapback-official','Snapback','You are essentially in a suburb of upstate New York, and getting out of Orchard Park is a genuine nightmare.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('3588c99b3eb5db46b8f5492b','venue','3814','atmosphere','snapback-official','Snapback','A Ravens night game is one of the loudest atmospheres anywhere. Mahomes himself said the only places he has had to go silent count are Baltimore and Seattle.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('588b8f4bfbed8376c589cc24','venue','3814','before','snapback-official','Snapback','The tailgate scene is strong. We have thrown 300 person tailgates here and the Ravens flock shows out.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('08303f81981dfecc806e5125','venue','3814','tips','snapback-official','Snapback','If you can, get a night game. A Blackout at the Bank is the version that teeters between A-tier and bucket list.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO reviews (id,scope,target_id,game_id,user_id,author,rating,body,created_at) VALUES ('snapback-review-3814','venue','3814',NULL,'snapback-official','Snapback',8,'Any Ravens game is a great time, but a night game at M&T Bank is something else, easily A-tier and teetering on bucket list.

The atmosphere is one of the loudest anywhere, Mahomes himself said the only places he has had to go silent count are Baltimore and Seattle. The flock shows out and the tailgate scene is strong, we have thrown 300 person tailgates here. If you can pick, get a Blackout night game, that is the version worth flying in for.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('a0513bd54c0f4fe07b3c48cd','venue','6501','best-seats','snapback-official','Snapback','Allegiant is a beautiful stadium and it hosted a Super Bowl. The games here tend to be high scoring, we caught an 84 point shootout.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('9406129119e84f154b9d2caa','venue','6501','tips','snapback-official','Snapback','Vegas can be the best or the worst weekend of your life, and that has nothing to do with the game. This is the highest-variance trip on the list, it depends on how you do at the casino.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('dc63808863f14f50f60e86a1','venue','7065','best-seats','snapback-official','Snapback','SoFi is a stunning stadium, genuinely one of the nicest you will see. The catch is it is nearly impossible to navigate.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('69e9fee279e7163b8e377311','venue','7065','atmosphere','snapback-official','Snapback','The atmosphere is underwhelming. The crowd noise is largely pumped in and you can end up surrounded by the visiting team fans.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('f11bc050e29b9a5713acb7e3','venue','7065','tips','snapback-official','Snapback','There is nothing super special about the Rams experience itself. LA is amazing but it is not really a football town. Go if you get free tickets.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('aa0556aacfbf5d2031685c90','venue','3679','before','snapback-official','Snapback','Hit the Muni Lot for some solid tailgating and genuinely wild costumes.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('88dc1165bba5f1cc6fbefc56','venue','3679','food','snapback-official','Snapback','The food inside is surprisingly tasty, and the fans are very passionate.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('95d15422e240f7bdf40c2d65','venue','3679','tips','snapback-official','Snapback','Two cautions, be ready for some grown men barking at you, and dress warm, it is on the water and gets very chilly. Cleveland as a city is wildly underrated.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('bc29e8f8b1f4d3b4c5a01b37','venue','1841','best-seats','snapback-official','Snapback','Almost every seat is a good seat here. We sat in section 333 row 8 worried about the view, and it was great.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('18e314d2845c3af44672a59b','venue','1841','food','snapback-official','Snapback','Try the carne asada fries, a solid stadium dish at about a 7. The LA street tacos are good too, a touch light on the cheese.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('fc3443c14d59a9fc2aecf994','venue','1841','atmosphere','snapback-official','Snapback','The arena is gorgeous and iconic, but the atmosphere can be lacking, lots of casual fans and a slow-to-fill crowd on weeknights.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('d6a54df9486caa070c0b2d21','venue','1830','food','snapback-official','Snapback','MSG has the best stadium food in America. Get the chop cheese from the new bodega stand, an 8.5. The pizza is fine but not the city''s best slice.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('cfc257eed9119502a3895f60','venue','1830','atmosphere','snapback-official','Snapback','Knicks fans are a tier above, they will celebrate a playoff series like they won a title. The padded seats are a nice touch.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('96e21093185d268ef4b41d51','venue','1830','getting-there','snapback-official','Snapback','Take the subway or walk, it is a huge money saver versus an expensive, traffic-heavy drive to most arenas.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('e3b3f5030eabdb4cd6fd3ed2','venue','1830','tips','snapback-official','Snapback','Tickets and food at MSG are pricey, that is the one knock. Everything else is elite.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('8c27b26ccde406875cf7d0ad','venue','1830','atmosphere','snapback-official','Snapback','The atmosphere can be a 10. Fans were on Embiid all night and even got him a technical, and the late pop moment when the whole arena erupts is unreal. The Knicks fans genuinely carry the team.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('b5160673c354a995446260f6','venue','1830','before','snapback-official','Snapback','There is a real ritual to it, even a prayer circle before the game. After a win the crowd floods the streets and the party spills onto Seventh Avenue.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO reviews (id,scope,target_id,game_id,user_id,author,rating,body,created_at) VALUES ('snapback-review-1830','venue','1830',NULL,'snapback-official','Snapback',8,'MSG lives up to the billing. The food is the best in America, no contest, get the chop cheese from the new bodega stand, it is an 8.5, and even the pizza is solid.

Knicks fans are a tier above, they will celebrate a playoff series like they won a title, and the padded seats are a nice touch. Getting there is easy and cheap if you take the subway or walk. The only real knock is the prices, tickets and concessions are steep. Iconic building, easily worth it.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('dd207d6b7086238aa89feaae','venue','1845','before','snapback-official','Snapback','The pregame setup is the coolest in sports. Wells Fargo, Lincoln Financial where the Eagles play, and the Phillies park are all in one complex. Inside there is a bar with big screens, cheesesteaks and pizza where you can watch the game if you cannot get a ticket.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('2fd98865efa2951d7c580ba9','venue','1845','food','snapback-official','Snapback','Get the Philly cheesesteak, it is fantastic, an 8.5. Their pizza slice is even better than New York. The arena food over-delivers.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('2f7224d196b0af1eb36d574e','venue','1845','atmosphere','snapback-official','Snapback','Sixers fans bring real edge and never disappoint, but do not let the away team take over your building. There is an underlying respect between Sixers and Knicks fans.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('40b969b3d9262419e0aceb37','venue','1845','best-seats','snapback-official','Snapback','Wells Fargo is newer than MSG with a slightly nicer concourse, but the seats themselves are nothing special, about a 7.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO reviews (id,scope,target_id,game_id,user_id,author,rating,body,created_at) VALUES ('snapback-review-1845','venue','1845',NULL,'snapback-official','Snapback',7,'Philly might have the coolest pregame setup in all of sports. Wells Fargo, the Eagles stadium, and the Phillies park are all in one complex, and inside there is a bar with big screens and cheesesteaks where you can watch the game even if you cannot get a ticket.

The cheesesteak is fantastic, an 8.5, and honestly their pizza slice beats New York. The arena is newer than MSG with a nicer concourse, though the seats are nothing special. The one knock the night we went, the home crowd let the away fans take over, which is the worst thing a fan base can do. Still a great experience and a can''t-miss if you get a playoff game.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('11cea0ccaa98dc9b04bbff8a','venue','1824','food','snapback-official','Snapback','Boston does food right. The fish is the best we have had at an arena, and the pizza is huge with a Chuck-E-Cheese vibe, which is a compliment, maybe the best arena pizza we have had. Food is a 7.5.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('e43f966fcf1e1b3c33491244','venue','1824','best-seats','snapback-official','Snapback','Courtside is unreal if you can swing it. The concourse and the seats are genuinely nice, this is a clean, well-run building.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('730ccfc65475b631cf5f0da3','venue','1824','atmosphere','snapback-official','Snapback','The crowd stays loud the entire game even in a blowout, and it is electric. Some of us called it the most electric place we have ever been, even over MSG. The city is lit after a win.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO reviews (id,scope,target_id,game_id,user_id,author,rating,body,created_at) VALUES ('snapback-review-1824','venue','1824',NULL,'snapback-official','Snapback',8,'TD Garden is a real basketball cathedral and our very close number two for NBA playoff experiences.

The crowd stays loud the whole game even in a blowout, and a couple of us called it the most electric place we have ever been, even over MSG. The food is a genuine surprise, the fish is the best we have had at an arena and the pizza is huge and great, a Chuck-E-Cheese vibe in the best way. The concourse and seats are nice, and if you can ever get courtside for a playoff game it is a 9.5 night. Boston after a win is lit. Easily a can''t-miss.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('9a884cd1f626332427812ec2','venue','1827','tips','snapback-official','Snapback','The most unique thing in the building is a real barber shop where you can get a haircut during the game. We have never seen another arena with one, and they even had exclusive Jeff Hamilton Hawks jackets.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('0c5ce5dbd1fe413da9dcf8da','venue','1827','food','snapback-official','Snapback','Food over-delivers. The concessions are all local Atlanta restaurants instead of generic chains, and the half slab of baby back ribs off an open-fire grill was one of the best stadium food items we have ever had, a 7, same as the Chiefs.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('74566717e4e465ca0af3d5c5','venue','1827','food','snapback-official','Snapback','Get the lemon pepper wings, it is an Atlanta thing, shout out Lou Will, just know they run small.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('7755c446ce69a074499dbd17','venue','1827','best-seats','snapback-official','Snapback','Stunning arena after the 2019 renovations with beautiful padded seats. The stadium itself is the highlight and carries the score.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('6b8b980f15351fc346bf62d4','venue','1827','atmosphere','snapback-official','Snapback','Atmosphere can be thin. We were told it was a sellout and it looked half empty with only a few rows in the fan section, but that was a midweek game with the Hawks resting starters against a bottom team. The fans we met were die-hards.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('097a7d194b73bfbd403df5fa','venue','1827','getting-there','snapback-official','Snapback','Mercedes-Benz Stadium where the Falcons play is a stone''s throw away, so you are right in the middle of the Atlanta sports district.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO reviews (id,scope,target_id,game_id,user_id,author,rating,body,created_at) VALUES ('snapback-review-1827','venue','1827',NULL,'snapback-official','Snapback',5,'State Farm Arena is genuinely nice, the 2019 renovations make it a stunning building with great padded seats, and it has the most unique feature we have seen anywhere, an actual barber shop where you can get a haircut during the game.

The food over-delivers too, all local Atlanta spots instead of generic chains, and the open-fire ribs were one of the best arena items we have ever had. The catch is the atmosphere. We were told it was a sellout and it looked half empty, but to be fair it was a midweek game with the Hawks resting starters against the worst team in the league. The fans we talked to were die-hards even though the online world treats the Hawks as the most hated team in the NBA, mostly over their against-the-spread betting record. Solid stadium, mid everything else, worth it on a big night.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('3f6ff8d9c287755af109d5b3','venue','43','tips','snapback-official','Snapback','The signature move here is McCovey Cove. Rent a kayak at Pier 40 and paddle out behind the stadium to try to catch a splash-hit home run. There have been 103 splash hits and only lefties have ever managed one, so watch the lineup. Bring friends and beers and do it once.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('133270737733e88aa77abe5b','venue','43','best-seats','snapback-official','Snapback','Oracle Park is as close to a perfect stadium as we have seen. It is luxurious and right on the water but still feels like a real ballpark, with green seats like Camden Yards. The Field Club behind home plate is incredible, and there is a Kid Zone and tons of features.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('c350292a1b51481895e958e8','venue','43','food','snapback-official','Snapback','The food might be the best in baseball. The crazy crab sandwich, the SoDo pastrami, and especially the caramel popcorn are unreal, possibly the best single item we have ever had at a stadium.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('1be476f862cb4ed108c6abe8','venue','43','atmosphere','snapback-official','Snapback','Fans are great and genuinely friendly, the cove crowd will hand you food, drinks, and sunscreen. It was not super rowdy the day we went, but a Giants playoff game would be loud.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('7ca4a568afcf21bfa326cb5f','venue','43','getting-there','snapback-official','Snapback','Stay near the ballpark, not downtown. The area right around Oracle Park and the cove is beautiful with bars outside, but skip lodging near Capitol Hill or City Hall.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO reviews (id,scope,target_id,game_id,user_id,author,rating,body,created_at) VALUES ('snapback-review-43','venue','43',NULL,'snapback-official','Snapback',8,'Oracle Park is one of the best ballparks in the country, the stadium itself is about as close to a 10 as we have ever scored one. It sits right on the water, feels luxurious but still like a real ballpark, green seats like Camden Yards.

The food is elite, the crab sandwich, the pastrami, and a caramel popcorn that might be the single best thing we have ever eaten at a stadium. The one-of-a-kind move is McCovey Cove, rent a kayak at Pier 40 and try to catch a splash-hit home run, it is a 9-plus for uniqueness, just know only lefties ever hit one out there and you will not actually watch much of the game.

Fans are friendly and the area around the park is great, just do not stay downtown near City Hall. A Giants game here is a must, and a playoff game would be even better.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('695ff7781872a05a92e148b0','venue','4242','atmosphere','snapback-official','Snapback','They have live music in the stadium and a famous sausage race you can even buy merch for. The retractable roof and tailgating scene add to the vibe.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('e53e986b3cb4cd61fab3c2e8','venue','4242','food','snapback-official','Snapback','The best item is the Wisconsin hot dog topped with cheese curds, a slice of cheese, cheese sauce and ranch. The sushi and spicy California roll were also surprisingly good, and there is a chicken parm sandwich.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('2b6f15e1005aa74f898e2506','venue','4242','tips','snapback-official','Snapback','If they say the roof is closed, prepare for it to feel over 120 degrees inside, so come ready for the heat. There is also a famous beer slide, though one ride for one person can cost around 500 dollars.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('3b72415184cc7c8b1e941bd5','venue','4242','getting-there','snapback-official','Snapback','It is a clean, navigable midsize ballpark and city, easy to get around compared to a big metropolis.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO reviews (id,scope,target_id,game_id,user_id,author,rating,body,created_at) VALUES ('snapback-review-4242','venue','4242',NULL,'snapback-official','Snapback',6,'A clean, solid ballpark with a fun retractable roof, sausage race and tailgating scene. The Wisconsin hot dog with cheese curds was the best food item. It is a nice but not standout stadium in a mid city.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('92a5f5c10a29425742d88732','venue','87','before','snapback-official','Snapback','Ballpark Village right outside has a great setup with bars where you can watch the game without buying a ticket, similar to the Wrigley rooftops vibe.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('4a0e52734ad479a89ee36645','venue','87','food','snapback-official','Snapback','Try the Stinger donut with chocolate and vanilla, which was a standout. The Slinger dog with nacho cheese and eggs was more divisive and rated lower.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('ba5eff1e6c59923dab147d72','venue','87','atmosphere','snapback-official','Snapback','Cardinals fans showed up, and the game opened with a leadoff home run that got the crowd on its feet. As with most baseball, the fan ceiling is moderate.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO reviews (id,scope,target_id,game_id,user_id,author,rating,body,created_at) VALUES ('snapback-review-87','venue','87',NULL,'snapback-official','Snapback',5,'A historic but fairly basic ballpark. Ballpark Village and the Build-A-Bear inside are nice touches, and the Stinger donut is worth getting, but the city and stadium felt average overall.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('ab1d61e17d21d7655762266a','venue','83','atmosphere','snapback-official','Snapback','The ballpark itself is not much special, but the view with the bridge and the river behind the outfield is stunning. The center field building looks like a steamboat.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('bffb2db9144d8812c4af8f5c','venue','83','food','snapback-official','Snapback','Get the Skyline chili cheese coneys, basically a hot dog with chili, cheese, onions and mustard. The stadium chili runs a bit soggy and runny, but it is still good.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('4707d4368dd6fdebd4698921','venue','83','getting-there','snapback-official','Snapback','It is close to Kentucky, so you can walk over the bridge between the two.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO reviews (id,scope,target_id,game_id,user_id,author,rating,body,created_at) VALUES ('snapback-review-83','venue','83',NULL,'snapback-official','Snapback',4,'A run-of-the-mill ballpark with a beautiful river-and-bridge view but little else that is unique. The Skyline chili coneys are the food highlight.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('271e1348db3eb4a5b7f2c979','venue','16','best-seats','snapback-official','Snapback','There is not a bad seat in the house, but the outfield bleachers are a party in their own right with beer snakes and cup snakes. Where you sit depends on when you get to the game.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('6657ae4473d3930a64b11460','venue','16','food','snapback-official','Snapback','The Shake Shack burger and fries under the center field bleachers are among the best stadium food anywhere. Doug''s Dogs in the bleachers rotate weekly, and the Greek fries come in a Cubs helmet you keep if you finish it. Tavern-style pizza, not deep dish, is the local way.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('bd399f2978f8dcf9c00c80df','venue','16','atmosphere','snapback-official','Snapback','The classic brick, ivy and the nearly 100-year-old manually operated scoreboard give it a magical, historic feel even after renovations. The bleachers are more of a social party scene than a watch-every-pitch crowd.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('46023c5a68c7ebc6490d3ca3','venue','16','before','snapback-official','Snapback','Wrigleyville has tons of pregame options. Sluggers is a great spot with batting cages, bar food and games.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('39ffaded01fae9a9b8c95be1','venue','16','tips','snapback-official','Snapback','Make sure you check out the Small Cheval under the center field bleachers, it is one of the best things there.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO reviews (id,scope,target_id,game_id,user_id,author,rating,body,created_at) VALUES ('snapback-review-16','venue','16',NULL,'snapback-official','Snapback',9,'Arguably the best stadium in sports. Iconic ivy, historic feel and not a bad seat in the house, with a party atmosphere in the bleachers. The Shake Shack burger and fries are some of the best stadium food we have had, and we caught a walk-off comeback here.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('4b703b2a622dc1e2693581e3','venue','47','food','snapback-official','Snapback','The pierogies with pot roast and pickles are a Pittsburgh staple and top-five stadium food, along with the renegade dog. There is also a Belgian waffle with candied bacon and chocolate-covered pretzels.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('b5ea588584c663eedcbb55da','venue','47','atmosphere','snapback-official','Snapback','Pirates fans were into it all game, and there is a fun made-up celebration where fans wave their keys for Ke''Bryan Hayes.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('11e96444692fd13a0e8e9d9d','venue','47','tips','snapback-official','Snapback','Pirates legend Manny Sanguillen sits outside his barbecue spot at PNC Park every single game, hanging with fans. There is also a solid Kid Zone.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('390d23cb4be338522cede6ae','venue','47','best-seats','snapback-official','Snapback','Widely considered one of the most breathtaking and underrated stadiums in baseball, with great views across the river.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO reviews (id,scope,target_id,game_id,user_id,author,rating,body,created_at) VALUES ('snapback-review-47','venue','47',NULL,'snapback-official','Snapback',7,'An underrated, breathtaking ballpark with top-five food in the pierogies and pot roast. Manny Sanguillen hanging at his barbecue spot every game is a unique touch. Fans were into it despite a rough game.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('0557b946d3caf4ca5ccb5f26','venue','84','before','snapback-official','Snapback','Xfinity Live just outside is the mecca for Philly pregame, with bars, food and a celebratory zip line setup when teams win. It is about 300 feet from the Rocky statue and a short walk to the stadium.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('b99e324efeec53e8c8dc28b0','venue','84','food','snapback-official','Snapback','Chickie''s and Pete''s crab fries (fries with Old Bay and cheese dip) are the signature item. Bull''s BBQ burnt ends cheesesteak is made fresh, but much of the other food is pre-made and not cooked fresh.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('32c0c7e9a57e4fef731108f1','venue','84','atmosphere','snapback-official','Snapback','Philly fans claim to be the best in sports and can approach a 10 in the playoffs, though a regular-season game is more muted. There is a kids zone with a milkshake bar.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('1cb9a0787e449f7559983300','venue','84','tips','snapback-official','Snapback','The Schwarber burger sounds and looks unremarkable and is not cooked fresh, but the flavors win you over.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO reviews (id,scope,target_id,game_id,user_id,author,rating,body,created_at) VALUES ('snapback-review-84','venue','84',NULL,'snapback-official','Snapback',6,'A good modern ballpark with one of the best pregame setups in sports at Xfinity Live. Most of the food is pre-made rather than fresh, which holds it back, but the crab fries and Bull''s BBQ stand out.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('e349581ba67f9d48edd0b9dd','venue','218','before','snapback-official','Snapback','The Battery is built right next to the park with bars and restaurants a stone''s throw away, known as the best pregame party in baseball. If rain hits you can duck into one of the inside bars.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('868e64dc03ea6a450b10e031','venue','218','best-seats','snapback-official','Snapback','The Chop House Club seats are for fans who want to party, with food delivery to your seat, a beer chiller, phone charger and ordering from your seat. It is one of the coolest seat setups around.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('a2f8f4982f44a7d023f8bd5b','venue','218','food','snapback-official','Snapback','The four-bagger is a giant novelty sandwich more marketing than taste, but the fielder''s catch po''boy with lobster tails, fried oysters and candied bacon, plus the wings, were excellent.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('5fac37f11f5e640f57aadc99','venue','218','atmosphere','snapback-official','Snapback','Braves Monument Garden is a Hall of Fame style museum inside the stadium, and there is a kids zone with whack-a-mole. The famous tomahawk chop can be electric in the playoffs but was quiet at a day game.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('c5b112b7741b5fcec8dcf323','venue','218','tips','snapback-official','Snapback','There is a zip line inside the stadium, likely the only ballpark where you can zip line, and it is a lot of fun.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO reviews (id,scope,target_id,game_id,user_id,author,rating,body,created_at) VALUES ('snapback-review-218','venue','218',NULL,'snapback-official','Snapback',7,'Known as the best party in baseball thanks to the Battery. The Chop House Club is one of the coolest seat setups around, there is a zip line and a museum inside, and the fielder''s catch po''boy is excellent. Fans were quiet at a rainy day blowout.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('0d3a084955306855dc97eb64','venue','3726','food','snapback-official','Snapback','The bacon-wrapped pork skewers were a standout, and the pulled pork nachos were solid. The stadium has good variety from hot dogs and pretzels to unique foods and food trucks right outside.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('ca6f95edb1a13c7697d89617','venue','3726','atmosphere','snapback-official','Snapback','The crowd is more chill and casual than SEC or rivalry games, and it took a Hail Mary and walk-off touchdown to really get the fans into it. Fans tend to leave early to beat the lines.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('fe5d6e9222e631c6db1aec92','venue','3726','best-seats','snapback-official','Snapback','The stadium is stunning and the Boulder campus and setting are a great time.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO reviews (id,scope,target_id,game_id,user_id,author,rating,body,created_at) VALUES ('snapback-review-3726','venue','3726',NULL,'snapback-official','Snapback',7,'A stunning stadium in a beautiful Boulder setting, but the fans are notably chill and casual, the lowest atmosphere we have rated. The pork skewers are great. Worth it especially while the Sanders-era novelty lasts.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('ca82f35674f679e7b611afe1','venue','3657','before','snapback-official','Snapback','Hit The Strip, a row of bars and restaurants like the Houndstooth, for the night-out scene. The campus tailgate scene on the Quad has rented white tents set up for you, which is why locals call it a cocktail party.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('d3f39c67927a724c55f70a7b','venue','3657','food','snapback-official','Snapback','The chicken salad sandwich with ranch, bacon and cheddar is a good combo, though the food is cold and prepackaged. Eat quick if you want to catch Dixieland Delight.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('f0fb60c5e24c8a7395f7fa11','venue','3657','atmosphere','snapback-official','Snapback','The fans are electric from Friday night through kickoff, and the place gets as loud as anywhere when the home team scores. The light show is amazing.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('15d5aacfe835196479198bb1','venue','3657','best-seats','snapback-official','Snapback','The bleacher seating is tight since they pack in as many people as possible, so manage expectations on legroom even with a great view.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('4598d74d1283dfd9cfc10bcd','venue','3657','tips','snapback-official','Snapback','Stop by the Walk of Champions and the Denny Chimes on campus before the game.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO reviews (id,scope,target_id,game_id,user_id,author,rating,body,created_at) VALUES ('snapback-review-3657','venue','3657',NULL,'snapback-official','Snapback',8,'It just means more here. The campus, tailgates and atmosphere are electric and the light show is stunning, capped by one of the greatest games we have seen. The stadium itself is fairly average with tight bleacher seating, and the food is cold and prepackaged.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('e93ecde5c2379024ec9056b4','venue','3853','atmosphere','snapback-official','Snapback','A checkerboard night game with Rocky Top is one of the greatest atmospheres in college football. The first defensive third down was the loudest stadium moment we have ever heard across 200-plus stadiums.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('983067fd0b776d5fa272e141','venue','3853','food','snapback-official','Snapback','The club-level brisket grilled cheese, New England lobster roll and Tennessee mac and cheese were some of the best stadium food we have ever had, though that is club section, not the regular concourse.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('af24844f68121a72d9bac1fb','venue','3853','best-seats','snapback-official','Snapback','There is not a bad seat in the house except one famous obstructed seat you have to peek around the edge of. The concourse can get clustered and crowded.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('f9b80305152f2eb9cc588da0','venue','3853','getting-there','snapback-official','Snapback','Getting an Uber after the game is nearly impossible and took over two hours, so plan your ride home in advance if staying off campus.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('bd2ec13e7902fedd5fb79325','venue','3853','tips','snapback-official','Snapback','Tour the campus landmarks like the Rock and Ayres Hall, and the Vol Navy fans tailgate on boats on the river.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO reviews (id,scope,target_id,game_id,user_id,author,rating,body,created_at) VALUES ('snapback-review-3853','venue','3853',NULL,'snapback-official','Snapback',8,'A checkerboard night game at Neyland is one of the best environments in college football, with the loudest stadium moment we have ever heard. The club-level food was among the best we have had. The concourse gets clustered and post-game Ubers are nearly impossible.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('d44adb4e7f018f9a287fc7ba','venue','3948','getting-there','snapback-official','Snapback','The stadium is not on campus, so plan for the drive. From the University of Miami area it took the crew about 57 minutes each way, and getting an Uber out after the game was a nightmare. The lot for the Ubers was a 35 minute walk from the seats, so leave early or expect a long wait.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('1754dfa4d239da2f837e5e60','venue','3948','best-seats','snapback-official','Snapback','It is a big, modern stadium and felt close to 90 percent filled for a rivalry game, but there are a lot of empty seats at kickoff. Student tickets are completely free.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('b8f9ceec13abba3bf8522f83','venue','3948','food','snapback-official','Snapback','The concourse food was a standout. The OG smash burger was one of the best stadium burgers they had ever had, and there is caviar on chicken on a bao bun that was outstanding. Skip the gyro, it looks better than it tastes.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('1e33556bfd0c2a4265918eda','venue','3948','atmosphere','snapback-official','Snapback','Rowdier than a Dolphins game, but the student turnout is light and a lot of fans are alumni rather than students. They pump in music. Tailgates outside range from chill to lit, and there are good ones if you find them.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('67bcdc67b0ceeceef1115f80','venue','3948','tips','snapback-official','Snapback','It is the same building the Miami Dolphins play in, so it is a quality but newer stadium with less tradition. Pair it with the F1 setup and the bridge nearby if it lines up.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('f80646bffe089a6140ce4c1e','venue','3948','atmosphere','snapback-official','Snapback','No-joke deafening and electric nonstop from both sides, close to a true 50/50 split rather than the corporate crowd you might expect. The energy in the entry line is constant chanting, and the second half reaches a genuine flow state. One of the loudest national championship environments you will find.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('42c7cc1c14770b73d656fff2','venue','3948','food','snapback-official','Snapback','Get Thor''s hammer, a novelty meat item that is usually all show, but this one came piping hot and pretty tender for stadium food and fed about 20 people around us. A rare novelty item that bangs on taste.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('818b153b3a1f0bd8c0b7539e','venue','3948','best-seats','snapback-official','Snapback','This open-air stadium is a real rarity this late in the season since most title games are in cold-weather domes. The sightlines are great even from the opposite side, and being outdoors elevates the whole experience.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('535bcd5b3b171e28dbf2d07a','venue','3948','before','snapback-official','Snapback','The tailgate scene outside is a fun, hyped environment with both fan bases starved for a championship. Even if you are not a big tailgater, the energy is impressive and worth getting there early for.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('a52550af5a23431995ef0f8f','venue','3948','tips','snapback-official','Snapback','A home national championship is incredibly rare since most big programs are in small college towns, so a title game actually held near a competing team''s home market is special. Getting in and out of the area was quick.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO reviews (id,scope,target_id,game_id,user_id,author,rating,body,created_at) VALUES ('snapback-review-3948','venue','3948',NULL,'snapback-official','Snapback',9,'Our highest-rated experience. Every category scored over 8.5: a piping-hot Thor''s hammer novelty food, unreal gameplay that came down to the final drive, a rare open-air championship stadium and a near 50/50 split crowd that was electric and deafening all night. The uniqueness of a home-market national championship plus the on-field access made it a perfect cap to the season.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('0e86547fb4e46d2d7169ee25','venue','208','getting-there','snapback-official','Snapback','The subway is the cheap way in at 2.90 each way to the Bronx. An Uber to the stadium ran 59 dollars, so the train is the move.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('7922bfd7249ba65c70dda03e','venue','208','best-seats','snapback-official','Snapback','Lower-level seats near the action delivered an unreal World Series atmosphere with fans on their feet for every at bat and pitch. Premium seats here ran over 1,500 dollars for two.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('bc7ebd2537023efbf26be7c1','venue','208','food','snapback-official','Snapback','The value bucket is about 10 chicken tenders and a huge pile of fries for 25 dollars, worth it for a group. The standout is the Lobel''s steak sandwich, freshly carved meat cooked perfect medium rare, highly recommended.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('ad11ef6baab331d968a78014','venue','208','atmosphere','snapback-official','Snapback','One of the best baseball atmospheres they have rated. Yankees fans were rowdy early, and when the Dodgers came back their fans were heckling right back, so everyone was into it. The fan reaction at the clinch was special.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('415b89e9b3a1977f102d73a1','venue','208','before','snapback-official','Snapback','There are some cool bars outside the stadium to hit before the game.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO reviews (id,scope,target_id,game_id,user_id,author,rating,body,created_at) VALUES ('snapback-review-208','venue','208',NULL,'snapback-official','Snapback',8,'An incredible, memorable World Series night and the second highest baseball atmosphere they have scored. Yankee Stadium itself is a fairly run-of-the-mill ballpark, but the history, the crowd, and the gameplay made it a need-to-have experience. If the Yankees ever get back, go.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('688f22216dd0fc4dc633f669','venue','347','best-seats','snapback-official','Snapback','It is a nice stadium, a bit better than your run-of-the-mill venue but not Sofi-level. Camp Randall has a beautiful fall setting that just feels like football.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('f6c11ce5d86e888b4fdd404d','venue','347','food','snapback-official','Snapback','The club section food was a tad underwhelming, the shrimp cocktail was good but there were no cheese curds in the club, which was a letdown. Get the brats. The regular concessions did not look like they would blow your socks off, so chase the cheese curds elsewhere.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('c8799faf7cc7bc7ebba25303','venue','347','atmosphere','snapback-official','Snapback','One of the best atmospheres they have seen. Jump Around between the third and fourth quarter makes the place bounce and this was one of the best Jump Arounds in years. Wisconsin is a football state and the fans are engaged the whole game.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('0f52dadab6003cb0f822b971','venue','347','before','snapback-official','Snapback','Madison is one of the best college towns in the country. State Street has pizza shops, ice cream, and live music right up to the capitol. The campus around Bascom Hall is stunning.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('9072a6692fb69ecf18f0223a','venue','347','tips','snapback-official','Snapback','Big game weekends can pair a Friday night basketball game at the Kohl Center with Saturday football, plus storming opportunities. Walk around the W crest on the field, do not step on it.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO reviews (id,scope,target_id,game_id,user_id,author,rating,body,created_at) VALUES ('snapback-review-347','venue','347',NULL,'snapback-official','Snapback',8,'Landed as their number one college football experience and top five all time. Madison is arguably the best college town in America, the campus is gorgeous, and Jump Around is special. The only thing missing was a winning football team. Deserves a spot in the top five all time.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('f0cb308878fdb79079077e6b','venue','3696','getting-there','snapback-official','Snapback','Super easy access. You can pull an Uber right to a step from the front gate and buy your tickets two minutes before kickoff. They sell paper tickets at the window starting at 5:30.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('775245fec16c1440b8bc2f2f','venue','3696','best-seats','snapback-official','Snapback','Wide open stadium with sight lines from pretty much everywhere, short bathroom lines, and you can find your friends easily. You can walk wherever you want, even on the field before the game.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('ea485a28f39b92f0d47d2a03','venue','3696','food','snapback-official','Snapback','Cheap food and short lines. They serve chick-fil-a and even chicken broth on the sideline on a cold night. Free pizza was floating around. Skip the cold pre-wrapped waffle, the ice cream was the better call.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('1843fad92db1186841497369','venue','3696','atmosphere','snapback-official','Snapback','A MACtion Tuesday night game with the worst team in college football, so it is empty like a video game, but it is a unique, low-key good time. First fans through the gate got a free scarf and hat with their ticket.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('ccb80ad1115f0f6d1c4677bd','venue','3696','tips','snapback-official','Snapback','It is free for students, the beer is cheap, and there is an underrated bar scene afterward around Water Street. Go once for the novelty.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO reviews (id,scope,target_id,game_id,user_id,author,rating,body,created_at) VALUES ('snapback-review-3696','venue','3696',NULL,'snapback-official','Snapback',5,'Not the worst experience in college football despite hosting the worst team. The free scarf and hat, field access, cheap food, short lines, and the pure novelty of a cold MACtion Tuesday night make it worth doing once, but probably not twice.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('52ba8eceb3c7083bc21d439f','venue','3795','best-seats','snapback-official','Snapback','A nice stadium that delivered an awesome split-crowd rivalry atmosphere when the Lone Star Showdown returned after 13 years.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('2622d4885c21e960da9fcd37','venue','3795','atmosphere','snapback-official','Snapback','The fans were honestly awesome and the rivalry game lived up to the hype. The yelling is a real tradition, they have yell leaders, not cheerleaders, and a midnight yell pep rally the night before every home game.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('eb95681502e3767a4405a5ea','venue','3795','before','snapback-official','Snapback','For a rivalry weekend, look for the over-the-top tailgates, including a whole cow roasted to feed hundreds of people.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('3458b8dfb25a2ceb1f6ca595','venue','3795','tips','snapback-official','Snapback','Campus is in the middle of nowhere College Station, so do not expect a college-town scene right outside the stadium.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO reviews (id,scope,target_id,game_id,user_id,author,rating,body,created_at) VALUES ('snapback-review-3795','venue','3795',NULL,'snapback-official','Snapback',7,'The return of the Texas A&M vs Texas rivalry made for one of the best rivalry atmospheres in college football, crowned the best rivalry over Ohio State vs Michigan on this trip. Great fans and traditions. The stadium is nice but campus is isolated and the gameplay was admittedly mid.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('fba5420be4278c00878563db','venue','3861','best-seats','snapback-official','Snapback','Ohio Stadium, the Shoe, is one of the most beautiful stadiums in college football. A split crowd right down the middle of the end zones is part of what makes the playoff games here pop.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('6d67236eb4ec505681010fe0','venue','3861','atmosphere','snapback-official','Snapback','For the Michigan rivalry game the noon kickoff hurt the atmosphere and it was quieter than expected. For the CFP home game against Tennessee it was the loudest the crowd has ever been here, even with a near 50/50 Vol takeover of the stadium. Bring red, the playoff game was a Scarlet out.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('e0a2259d721c2d582028c4da','venue','3861','food','snapback-official','Snapback','Collect the free towels they hand out. Standard stadium concessions otherwise.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('dccd006abcc004dfd25ecafa','venue','3861','tips','snapback-official','Snapback','The playoff forces the home team to play the away team''s hype video, which can backfire when half the building is the visiting fan base. Big noon kickoffs can sap the energy compared to a night game.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('0c0a1dfaab4803195689e948','venue','3861','before','snapback-official','Snapback','Campus and the stadium are both beautiful. In Columbus, the Short North has bar after bar packed on game day.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('aab8c2379642ca9f708995fe','venue','3861','atmosphere','snapback-official','Snapback','The Shoe gets loud and packs a huge scarlet-out crowd, and on TV it sounded like it was rocking, but from the upper deck it did not feel deafening. The lower bowl is where the sound filters down, so the best energy is closer to the field.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('0fea09485c7e37f7e93613e0','venue','3861','food','snapback-official','Snapback','The stadium food has stayed the same for years and is pretty run-of-the-mill. Do not expect standout concession options inside the stadium itself.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('7accdcff8420ff60cda2889f','venue','3861','before','snapback-official','Snapback','The campus is genuinely beautiful and worth walking. See Thompson Library and the Oval, two of the prettiest spots on a top-three-largest campus in the country, on your way toward the stadium.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('f4b2fb1a894d6e33eae6284b','venue','3861','tips','snapback-official','Snapback','The campus team store and bookstore are stacked with gear, including LeBron James collabs since he reps the school. Great pregame stop if you want merch before the game.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO reviews (id,scope,target_id,game_id,user_id,author,rating,body,created_at) VALUES ('snapback-review-3861','venue','3861',NULL,'snapback-official','Snapback',8,'The Shoe earns its reputation. The Tennessee CFP home game was the loudest the building has ever been and took the top spot among the playoff home games at the time, while the Michigan rivalry game suffered from a flat noon-kickoff crowd and bad gameplay. A beautiful stadium that comes alive for the biggest games.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('1f68d5eade01aa541b71872d','venue','3855','best-seats','snapback-official','Snapback','The Cathedral of college football. It is one big classic bowl with the famous golden dome and Touchdown Jesus nearby. The seats are old-style, the place just feels legit and historic.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('020e560096bc25734e735bcb','venue','3855','food','snapback-official','Snapback','They do not sell booze inside, so know that going in. Standard stadium food otherwise.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('4f8960d7695bb86ede5b9b41','venue','3855','atmosphere','snapback-official','Snapback','The fan section felt a little weak on the opening kickoff compared to the Penn State intro, but the pregame fireworks and the setting are electric. The first-ever 12-team playoff home game atmosphere was strong.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('bf6373bdaea8d5cd7b8927e1','venue','3855','before','snapback-official','Snapback','Far and away the best bookstore they have seen on the tour, you can drop serious money there. The tailgate scene is unlike any other, and visiting fans, especially in a cold playoff game, are friendly.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('ba0a3a6f9e9c306a4f4e1b83','venue','3855','tips','snapback-official','Snapback','Dress warm, it can snow. South Bend gets genuine playoff cold.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO reviews (id,scope,target_id,game_id,user_id,author,rating,body,created_at) VALUES ('snapback-review-3855','venue','3855',NULL,'snapback-official','Snapback',7,'The first-ever CFP home game at the Cathedral of college football. The history, the golden dome, the elite bookstore, and the tailgates make it special, and Notre Dame put on a professional playoff performance. The atmosphere was good but not quite the loudest, landing it as a strong but not chart-topping playoff experience.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('b8f819275ff6cac593ac80f5','venue','3910','best-seats','snapback-official','Snapback','Texas wears one of the most beautiful, clean college football looks and the field views are great. A nice stadium overall.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('8890b8dbecc2b1d11c8f281a','venue','3910','food','snapback-official','Snapback','The corn dog at DKR is a solid stadium food pick, get it with mustard.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('9152e1bd45b685286b79513d','venue','3910','atmosphere','snapback-official','Snapback','For the CFP first-round game the crowd was sleepy and a bit quiet pregame, partly because students were on winter break. It picked up but never reached the buzz of a traditional college town.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('d4dc086dfd4d6301c6cc59d7','venue','3910','before','snapback-official','Snapback','Austin is not a traditional college town, so the frat and bar buzz around the stadium is lighter than places like State College, but the city itself is great.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO reviews (id,scope,target_id,game_id,user_id,author,rating,body,created_at) VALUES ('snapback-review-3910','venue','3910',NULL,'snapback-official','Snapback',7,'Texas hosting a CFP home game at DKR. The stadium and uniforms are beautiful and the city is great, but the atmosphere was a touch flat with students on winter break and Austin not being a classic college town. A blowout win kept it from climbing higher, landing just under the other playoff home games.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('98908fe9346da9b773d26365','venue','5348','best-seats','snapback-official','Snapback','A gorgeous modern dome built for big events. Comfortable, far more enjoyable for comfort than an old barn, and the upper-deck capacity is the thing to watch for a neutral-site game with a cheap ticket.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('71203d1e83b0eb12b33c88ab','venue','5348','food','snapback-official','Snapback','The Taffer Grill common-folk food is genuinely good and does not break the bank, tip the cap. If you have suite access, the mac and cheese is outstanding. Stadium pricing on the concourse is cheap and good.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('a7f2eb45957512a06bf6b471','venue','5348','atmosphere','snapback-official','Snapback','For the Peach Bowl CFP quarterfinal the crowd was sleepy and there were a lot of empty seats until a great game woke them up, then it became one of the better atmospheres once it went to double overtime.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('821b4985786d4cd01c182758','venue','5348','getting-there','snapback-official','Snapback','The College Football Hall of Fame is right next door, a great pre-game stop with plenty of merch.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('0d0e598760cff168e7205814','venue','5348','tips','snapback-official','Snapback','Neutral-site playoff games here can have very cheap tickets, get-in was 19 dollars, and a sleepy crowd, but a barn-burner game can rescue the whole atmosphere.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('20c3a2ac8499b5ece2ed1b84','venue','5348','getting-there','snapback-official','Snapback','Stadium traffic getting in and out is brutal, on par with Jerry World. You cannot move freely throughout the stadium, so build in extra time.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('cbf199195b368f606648947e','venue','5348','food','snapback-official','Snapback','The 40 dollar Barbecue Box (chicken thighs, ribs, apple pie, coleslaw, beans, cornbread) is fire and they only sell about 200 of them. The cornbread was the best stadium food anyone on the crew had ever had. Also a rare chance to eat Chick-fil-A inside since the championship is on a Monday, plus Roosters ice cream that is incredibly creamy.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('28e18cf11647709d5bf1f04b','venue','5348','tips','snapback-official','Snapback','Concession prices are very affordable here compared to most stadiums, which is a big plus for a championship event.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('16f1aeb56ca7dc52604ef17a','venue','5348','atmosphere','snapback-official','Snapback','Beautiful modern arena and a great host city in Atlanta. The National Championship crowd felt like legit fans, though you need a good bit of cash to get in. It was roughly 12 to 15 degrees in Atlanta for this game, so dress warm.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO reviews (id,scope,target_id,game_id,user_id,author,rating,body,created_at) VALUES ('snapback-review-5348','venue','5348',NULL,'snapback-official','Snapback',7,'A well-deserving host for the national championship in a beautiful modern stadium with surprisingly affordable concession prices and enough die-hard fans to feel real anxiety as the game came down to one possession. The final Snapback experience score was a 7.4, landing it in the one-and-done tier. Worth the trip when your team is in the big game, but the brutal in-and-out traffic holds it back.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('255c1af0c9f55691a6ae8c41','venue','1056','getting-there','snapback-official','Snapback','Parking lots are literally on a golf course, you tailgate on the fairways, which is a unique and great setup. It was about a 40 minute drive from LA with no traffic on New Year''s Day.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('e6ec5bbc3e02f49999a3158e','venue','1056','best-seats','snapback-official','Snapback','One continuous bowl with no upper, lower, or 400 levels, so there is genuinely not a bad seat in the house. The seats are tight with no legroom though, so short fans fare better. A split crowd right down the middle of the end zones is part of the charm.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('9b89d2aa74dfe78d1729923f','venue','1056','food','snapback-official','Snapback','Do not miss the lumpia, a Filipino egg roll that was maybe the best stadium food they have eaten in over 100 events. Lines for food and bathrooms were short and well organized.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('0b5ddb8610fa40a7cf881517','venue','1056','atmosphere','snapback-official','Snapback','Loud for both fan bases with a great split crowd. Games are scheduled so the sun sets behind the hills between the third and fourth quarter, which is beautiful. Premium seating gets you a premium tailgate beforehand.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('ae19c74ba7e5dd1ad48cea2c','venue','1056','tips','snapback-official','Snapback','The granddaddy of them all, played once a year on a national historic landmark. The Rose Bowl gear is elite, the merch holds value. Try to catch the New Year''s parade in the morning.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO reviews (id,scope,target_id,game_id,user_id,author,rating,body,created_at) VALUES ('snapback-review-1056','venue','1056',NULL,'snapback-official','Snapback',8,'The granddaddy of them all earned the top score of the entire CFP tour. The golf-course tailgates, the single-bowl design with no bad seat, the lumpia, and the third-quarter sunset over the hills make it feel like a bucket-list event. So much prestige and tradition, only just missing the Rose Bowl parade itself.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('fc3430b1f6e8ee0b522a67c5','venue','7317','getting-there','snapback-official','Snapback','Plan for a bottleneck leaving the building.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('86fdea19fee1984bc728ed29','venue','7317','best-seats','snapback-official','Snapback','The premium suite seats are comfy but have a bit of a bar in front, so you have to lean up to get a clear view of the floor.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('fb47a3a968fb0a72c96be533','venue','7317','food','snapback-official','Snapback','Suite spread had burnt ends, brisket, beef tacos, quesadillas, steak sliders, chicken wings and egg rolls. The steak slider was a surprise standout. The wings needed sauce.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('02b00bde0003226fcb8bf42a','venue','7317','atmosphere','snapback-official','Snapback','Brand new arena and a solid crowd for what is effectively a Spurs home game in Austin. The split skewed toward Spurs fans rather than the Texas student or KD-jersey crowd you might expect. Note the Texas and KD signage gets blacked out for the NBA broadcast.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('c8498e09c7467a58b4ac71d3','venue','7317','tips','snapback-official','Snapback','The Spurs play here a couple of nights in a row as part of the I-35 series because the San Antonio Rodeo pushes them out of town, so you can catch back-to-back games.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO reviews (id,scope,target_id,game_id,user_id,author,rating,body,created_at) VALUES ('snapback-review-7317','venue','7317',NULL,'snapback-official','Snapback',7,'A fun NBA experience if you are in Austin, with a nice new arena and good suite food, but it played out like a standard Spurs home game rather than the Kevin Durant homecoming we expected. With Wembanyama ruled out for the season and the Spurs pulling away, it lacked a special moment. Final Snapback experience score was a 6.73.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('6bc6fcc0f34e6667baefa62d','venue','516','best-seats','snapback-official','Snapback','Even up high there is not a bad view in the house. This was the most expensive regular season Mavs ticket in history, so you do not need to go all the way down to get a great vantage point.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('c5a04d2566395e43e0993333','venue','516','food','snapback-official','Snapback','The Texas cheese steak sandwich is the food item of the game, about 20 dollars and comes with chips. Good ratio of ingredients and very good bread, though the onions tend to pile up on the edge rather than disperse.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('89900b583be864bef7dfeeae','venue','516','atmosphere','snapback-official','Snapback','An electric but emotional crowd for Luka''s return in a Lakers jersey. Expect constant Fire Nico chants at the free-throw line, MVP chants for Luka, a tribute video and a standing ovation. It felt almost like a funeral or memorial before turning into a celebration.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('5dedb5380165fd385b1a39bd','venue','516','getting-there','snapback-official','Snapback','Huge bottleneck leaving the arena after the game.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO reviews (id,scope,target_id,game_id,user_id,author,rating,body,created_at) VALUES ('snapback-review-516','venue','516',NULL,'snapback-official','Snapback',7,'One of the single most unique sporting events you can attend, seeing a superstar return after one of the biggest trades in sports history and torch his old team for 45 points while still getting a standing ovation. The arena is one of the nicest around with no bad views. Gameplay turned into a blowout so it lost the back-and-forth, but the atmosphere and uniqueness carried it to a 7.45 final score.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('13544ee1167dd55dc4111a99','venue','10642','getting-there','snapback-official','Snapback','Entry is all Face ID. Once you set up the app you can walk straight through the door without pulling out your phone, and getting in took under a minute. The same tech lets you grab merch or food and just walk out without scanning.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('b1e027592d164814adc4cc88','venue','10642','food','snapback-official','Snapback','Only two food spots, Pick and Roll and Fast Break, because the whole design pushes you to watch the game. Lines are quick in and out. The 16 dollar double cheeseburger is solid, but club prices are not included and run high.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('39ea7649d15eaa2fefd4d71e','venue','10642','best-seats','snapback-official','Snapback','Every single seat has a USB-C charging port. The top corner seats are steep and the worst in the house but went for about 15 dollars and are worth it. The lower bowl is essentially all club section.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('cba7004d23727e6a7d37b77f','venue','10642','atmosphere','snapback-official','Snapback','The much-hyped Clippers Wall behind the basket (the first 13 rows are standing-only swell seats) feels a bit forced and was not as rowdy as advertised, partly due to LA traffic and low attendance. The 40,000-square-foot Halo board overhead is insane.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('26e203ddf574f89384ff1907','venue','10642','tips','snapback-official','Snapback','Most teams play the Clippers and Lakers back to back on the West Coast road trip, so catch your team here. It is a cooler experience and about half the price of the Lakers.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO reviews (id,scope,target_id,game_id,user_id,author,rating,body,created_at) VALUES ('snapback-review-10642','venue','10642',NULL,'snapback-official','Snapback',7,'Steve Ballmer''s 2 billion dollar arena is a state-of-the-art masterpiece with Face ID entry, charging ports at every seat and a massive Halo board. The one thing money has not yet bought is the fan energy, as the Clippers Wall feels forced rather than the European-soccer atmosphere it was meant to be. A strong stadium and gameplay score offset a weak fans-and-atmosphere score for a 7.42 final, one of the higher NBA experiences.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('da733fd6ee9dbb3b67665125','venue','5404','atmosphere','snapback-official','Snapback','One of the best basketball environments you will ever be in. The crowd was so loud during the Pistons comeback that ears were ringing for days, with spontaneous Detroit Basketball chants breaking out from the stands. Their first home playoff game in over 15 years made the building electric.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('17c20743ed22c0cd197c6991','venue','5404','food','snapback-official','Snapback','The 313 Grill smash burger is above-average stadium food with caramelized onions, served very hot, paired with decent fries. Little Caesars is also available in-arena if you want the on-the-nose option.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('1dd8552ca18885c44f39bcd8','venue','5404','stadium','snapback-official','Snapback','Really nice arena with an open-air feel and good views. The Pistons stepped it up for the playoffs.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('5f1b8e27874fb094d1316751','venue','5404','tips','snapback-official','Snapback','If the Pistons are back in the playoffs and you live near Detroit, highly recommend going. Few fan bases are as passionate.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO reviews (id,scope,target_id,game_id,user_id,author,rating,body,created_at) VALUES ('snapback-review-5404','venue','5404',NULL,'snapback-official','Snapback',8,'One of the best playoff games and atmospheres ever witnessed in person, a back-and-forth thriller between the Pistons and Knicks with incredible shot-making from Cade Cunningham, Jalen Brunson and Karl-Anthony Towns. Detroit lost on a controversial no-call that was later admitted to be a foul, which kept it from going even higher, but the passion of the crowd in their first home playoff game in over 15 years made it special. Final score was an 8.03, the 10th highest ever given.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('178c15c93489f55fb0b36a4c','venue','3739','atmosphere','snapback-official','Snapback','The crowd is small and a lot of it crams under the one shaded section of the stadium, but everyone there genuinely wants to be there. Loud and excited in the parking lots, ready for what they came to see.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('9394ad82e5da2b164d5d3a82','venue','3739','before','snapback-official','Snapback','The pregame parking-lot scene had immaculate vibes with cornhole, a car show, food trucks, and a live band. There is also a rocket attraction nearby aimed toward Bowling Green''s stadium 25 miles south.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('a5d5dcaf058395690db8a075','venue','3739','food','snapback-official','Snapback','Do not expect much Italian cuisine at the tailgates despite the theme. It was mostly beer and standard fare. The suite level had actual Italian food: meatballs, mozzarella, bread, and a tiramisu type dessert.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('fdc4487543864421873ea5bc','venue','3739','best-seats','snapback-official','Snapback','Upgrading to a VIP suite cost only about 10 dollars more than a regular ticket and got free Italian food and drink. Worth the small upgrade.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('1364fe2d41606dbaab0172d0','venue','3739','tips','snapback-official','Snapback','You can walk right onto the field pregame with no one checking anything. Access here is wide open, which is part of what makes it unique. Bring sunscreen and water because the sun fries the open stadium for hours.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO reviews (id,scope,target_id,game_id,user_id,author,rating,body,created_at) VALUES ('snapback-review-3739','venue','3739',NULL,'snapback-official','Snapback',5,'An unusual but fun day watching the Italian professional football league play their championship in Toledo. The players truly love the game and smashed low expectations, but it was a blowout snoozer and the small stadium sat mostly empty in blistering heat. Go for the novelty and the open-container, welcoming city, not for elite football.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('71066404421222da9c951445','venue','3610','before','snapback-official','Snapback','The tailgates are a chill, family-and-community vibe rather than rowdy. The Warrior Walk where the team arrives is a highlight. Locals love to party and are extremely welcoming, so get there early.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('533ae70e86d9aa164201d6af','venue','3610','atmosphere','snapback-official','Snapback','The crowd starts as a packed sellout white-out and the team entrance is electric, but fans trickle out by the fourth quarter and it is a less rowdy, more laid-back game-day feel than a big SEC environment.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('231e8a0feae5d32bbf39a889','venue','3610','food','snapback-official','Snapback','Food trucks ring the stadium with endless options and cuisines. Standouts included the Hawaiian blue cheeseburger and a katsu plate. Try a spam musubi. Tons of variety for everyone in your group.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('9e7bb4669386284bcda810f2','venue','3610','tips','snapback-official','Snapback','Learn a couple local words: chee-hoo is the celebration yell when the team scores, and use ''you like go'' as an invite. Fans appreciate it. It is a true bucket-list, once-in-a-lifetime trip.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('5a932919c37105e275e90bc6','venue','3610','getting-there','snapback-official','Snapback','It is a long haul to get here, multiple flights from the mainland, but being in beautiful Honolulu makes it worth it. The setting and paradise location are a huge part of the draw.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO reviews (id,scope,target_id,game_id,user_id,author,rating,body,created_at) VALUES ('snapback-review-3610','venue','3610',NULL,'snapback-official','Snapback',7,'A bucket-list, once-in-a-lifetime college football experience in paradise. The food-truck spread is incredible, the locals take care of you better than anywhere, and the trip itself is unmatched for uniqueness. The fan atmosphere is more laid-back than a big SEC night game, and it is currently a temporary stadium, so the score lands strong but short of the top tier.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('30b6d6b707bfc48cdb540f1a','venue','3787','before','snapback-official','Snapback','Chapel Hill is underrated and the pregame scene is great. Franklin Street has a real buzz, and the campus is beautiful with the bell tower and the well where they say drinking on the first day of class gets you straight A''s.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('56219f1e5a68fa730a6a15de','venue','3787','atmosphere','snapback-official','Snapback','It is a wine-and-cheese crowd, more khakis and quarter-zips than deafening noise. Compared to a 19th hole at a golf course. Big pregame buzz but the in-stadium sound is not overwhelming, especially in a blowout.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('971a11ab4362ff2820714cc7','venue','3787','food','snapback-official','Snapback','Solid pass-fail college food. The foot-long Carolina dog with chili, slaw, and onions surprisingly worked and was not too messy. There is also a Bojangles stand, though the chicken fingers ran overdone.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('1e682894ec3dcd830ecae30e','venue','3787','food','snapback-official','Snapback','For a great pregame bite off campus, Merritt''s is highly requested for its BLT on sourdough, served in small, double, or triple sizes with a lot of bacon.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('16b76347de1e0e51c9c8587b','venue','3787','tips','snapback-official','Snapback','You can walk onto the field at UNC during business hours, one of only a few power-five schools where that is allowed. The bookstore is excellent, near Notre Dame tier, loaded with Carolina blue and argyle gear.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO reviews (id,scope,target_id,game_id,user_id,author,rating,body,created_at) VALUES ('snapback-review-3787','venue','3787',NULL,'snapback-official','Snapback',7,'Bill Belichick''s college debut brought a unique buzz and Chapel Hill is a great college town with an underrated Franklin Street pregame. The crowd is more wine-and-cheese than rowdy, and the game itself was a 48-14 blowout, but the campus, town feel, and novelty made it a strong experience.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('9a971bd7f1878aa5fe3bfeb9','venue','3626','best-seats','snapback-official','Snapback','There is not a bad seat in the building. Every single seat gives you a great view, and even though it is a smaller stadium fitting around 50,000, the sightlines are beautiful from anywhere.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('4d073eac4ef6cc911c388064','venue','3626','atmosphere','snapback-official','Snapback','Autzen gets insanely loud even for an early kick against a bad opponent. The fans showed out and it was phenomenal for the first couple quarters. When the motorcycle revs at the entrance it sends chills through your whole body and kicks up turf.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('fd1f980f6f8e528d7984b897','venue','3626','food','snapback-official','Snapback','Concessions like the Big Ten buffalo chicken slider and the hamburger were good but ran about $30 each, so not a strong value. The ice cream sandwich was fantastic.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('c19712a40fa5846ea9cbd2a4','venue','3626','before','snapback-official','Snapback','Track Town Pizza is the famous spot but it leans more nostalgia these days. Eugene is a very nice college town, though it can feel empty before students return for the term.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('052eecab1c5b5bf890eec247','venue','3626','tips','snapback-official','Snapback','Check the schedule before booking. The school runs on quarters/trimesters so early-season games can happen before students are back on campus, which dampens the buzz around bars and tailgates.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO reviews (id,scope,target_id,game_id,user_id,author,rating,body,created_at) VALUES ('snapback-review-3626','venue','3626',NULL,'snapback-official','Snapback',7,'A beautiful stadium with phenomenal fans and a great college town in Eugene. We hit it during a blowout before students were back, so it landed in the low sevens, but for a big game this place rates much higher. Worth a return trip.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('e8457b83731ad48ee45db577','venue','3654','food','snapback-official','Snapback','Every ticket now comes with all-you-can-eat concessions. The selection is big enough to satisfy you, the hot dogs are solid, popcorn is fresh and nachos are good. The main miss is no burgers or chicken tenders in the included menu.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('f9a66f6666fabe63a0598a6d','venue','3654','atmosphere','snapback-official','Snapback','The pregame intro and fireworks were electric, but a lot of fans leave at halftime to hit the bars, so the energy drops as the game goes on.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('4aaffbd21a0725658528865d','venue','3654','best-seats','snapback-official','Snapback','They recently put in field suites that are pretty nice for the size of the school.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('fe82dab3f69e56872fb65547','venue','3654','before','snapback-official','Snapback','Conway is near Myrtle Beach so you can play a round of golf, and there is a decent going-out scene. Best in early fall when the weather is still beautiful.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('8048c2a82bbc1afb0eb39854','venue','3654','tips','snapback-official','Snapback','The teal turf is unique. Talk to students pregame and you''ll get an honest read on the matchup; they were upfront that the game would be a blowout.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO reviews (id,scope,target_id,game_id,user_id,author,rating,body,created_at) VALUES ('snapback-review-3654','venue','3654',NULL,'snapback-official','Snapback',6,'The free all-you-can-eat concessions are a genuinely unique draw and a fun non-power-four experience. The fans leaving at halftime and a brutal blowout drag it down, but it is still something worth getting out to if you''re in the Myrtle Beach area in early fall.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('8440377743188900dfce0348','venue','3974','before','snapback-official','Snapback','The Grove is the headline tailgate and many call it the greatest in college football. Tents go up the morning of, you can walk into nearly any tent and they will feed you a full plate, and the southern hospitality is real. You can rent tents, big cups and speakers.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('26a391da9711e270c6ffcbac','venue','3974','atmosphere','snapback-official','Snapback','Inside the stadium the crowd was honestly underwhelming for a non-conference game. Everyone says come back for an SEC night game like LSU for the real loud atmosphere. Fans leave at halftime, partly because it gets very hot.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('9918bc0fcaf1761846a66f5b','venue','3974','food','snapback-official','Snapback','Stadium food was poor. The barbecue nachos came out cold and the Grove Burger had a sneaky onion and was not cooked well. The one perk is they have Chick-fil-A inside.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('a55b909216734bab39c4a24f','venue','3974','best-seats','snapback-official','Snapback','Really nice stadium where it feels like there is not a bad seat in the house at around 60,000 to 65,000.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('d74e8c5e27b03c5bd33776d5','venue','3974','tips','snapback-official','Snapback','Get there at 6 a.m. to claim Grove tent space on a big weekend. Oxford itself is a great college town with good bars and eats and is not far from the airport.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO reviews (id,scope,target_id,game_id,user_id,author,rating,body,created_at) VALUES ('snapback-review-3974','venue','3974',NULL,'snapback-official','Snapback',6,'The Grove tailgate is phenomenal and incredibly welcoming, and Oxford is a great college town. But the in-stadium atmosphere was quieter than expected for this game and the stadium food was garbage. Come back for an SEC opponent at night and the score would be much higher.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('bad24f11ba3c01ab8ef5b460','venue','3834','atmosphere','snapback-official','Snapback','An 85,000-seat stadium that packs out and stays on its feet even for a 3:30 Michigan State game. This is a fan base that cares deeply, and they are very welcoming, friendlier than the SEC crowds. Raiola coming out through the smoke gave goosebumps.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('7f8145799cc9ecbdc45ce6ce','venue','3834','food','snapback-official','Snapback','Get the Runza, the German-immigrant ground beef and cabbage sandwich. It''s polarizing drunk-food and heavy on onions, so skip it if you don''t like onions. The Corn Husker Crusher beer is easy to drink.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('55e2e99f68773d459d91911a','venue','3834','before','snapback-official','Snapback','The student tailgate is in the Nebraska Union in the middle of campus, a five-minute walk to the stadium, and drinking rules are not enforced there. Downtown Lincoln, the Railyard area, has a lot of bars and restaurants.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('db66ba5d99a0c568241f6e29','venue','3834','tips','snapback-official','Snapback','Before the game balloons are released after the first score, a unique authentic tradition they had to bring back. They run nearly every home game as a red out.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO reviews (id,scope,target_id,game_id,user_id,author,rating,body,created_at) VALUES ('snapback-review-3834','venue','3834',NULL,'snapback-official','Snapback',8,'A must-see if you are a college football junkie. The fans get it, the stadium packs out and stays loud, and downtown Lincoln surprised us with a great bar and restaurant scene. One of the warmest, most welcoming fan bases we have been around.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('c7e759e743cf753cac692295','venue','3801','atmosphere','snapback-official','Snapback','One of the loudest stadiums we have been in, and it stays loud consistently from start to finish, not just for a few minutes. The student section is electric, and the commercial-break entertainment with lights, music and dancing keeps everyone engaged.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('d8eb3cc57b7f03aad792bd63','venue','3801','food','snapback-official','Snapback','Get the Cougar Tail, an 18-inch maple (or blueberry) donut. Note this is a sober crowd, so the famous local move is energy drinks and soda. The Swig soda shops and candy are a thing here.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('9e5e66b891a1110ceab427fc','venue','3801','best-seats','snapback-official','Snapback','Stunning backdrop with the mountains behind the stadium. The royal-blue uniforms pop and there is not a bad seat.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('550b91d9127628d9636bc608','venue','3801','before','snapback-official','Snapback','Provo surprised us, a much better town than expected. There is one tailgate, the Blue Crew, where fans actually drink; the rest of the scene is sober and more low-key. True Religion is a great breakfast spot.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('635975b8c519cf0c8a5dc813','venue','3801','tips','snapback-official','Snapback','This is the Holy War rivalry with Utah, church versus state, and it is genuinely bloodthirsty and underrated. Go for the rivalry game for the full experience.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO reviews (id,scope,target_id,game_id,user_id,author,rating,body,created_at) VALUES ('snapback-review-3801','venue','3801',NULL,'snapback-official','Snapback',9,'Took the number one spot on our scale. The fans and atmosphere reached the nines, Provo blew us away as a town, the mountain backdrop is a cheat code, and the Holy War rivalry energy was out of control. An unforgettable student-section experience.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('fa1687013b028b376b7bfee0','venue','3772','before','snapback-official','Snapback','Ames has one of the best tailgate scenes in the country. The lots fill for miles with RVs, and even on a three-game losing streak in 40-degree rain everyone shows up and stays. This is where the real Iowa farmers and engineers go, more than Iowa City.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('397eb1d2a3b304d5e97d8e9f','venue','3772','atmosphere','snapback-official','Snapback','Notably, the colder and rainier it got, the louder the student section got. They hold down and do not leave. It is not the loudest stadium ever but the fans are loyal and built for the weather.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('64a6684fdbbb7adf964bd7da','venue','3772','food','snapback-official','Snapback','Standard stadium fare. The foot-long specialty corn dog and the chili cheese nachos are solid; getting chili on the nachos feels right for Iowa. Caramel kettle corn is a good add.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('2ab3fa13335c9c137fd68fd0','venue','3772','tips','snapback-official','Snapback','Walk through the Jack Trice barrier monument, the only FBS stadium named after a Black athlete, a cool tradition with great attention to detail. They sell no booze inside but allow re-entry, so you can go back to the car.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('962db5fcc9399deecf4e3bfa','venue','3772','best-seats','snapback-official','Snapback','Visit the Campanile bell tower on campus; tradition says kissing your soulmate under it at noon makes you a real student.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO reviews (id,scope,target_id,game_id,user_id,author,rating,body,created_at) VALUES ('snapback-review-3772','venue','3772',NULL,'snapback-official','Snapback',6,'Easy-living Midwest college football. The stadium and crowd are not the loudest or fanciest, and our game had low stakes, but the tailgate is among the best anywhere and the fan loyalty in cold rain is impressive. Ames would be awesome for a big game.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('9a4ec60b78a0980ea015a97a','venue','3784','before','snapback-official','Snapback','Raiderville is a massive multi-day camp-out party outside the stadium with students living in tents and playing sports for days before a big game. The week-long energy and barbecue in Lubbock are incredible, the best campus barbecue we have had (try the burnt ends).','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('c67c4378bd14cca567c2e706','venue','3784','food','snapback-official','Snapback','In-stadium food beat expectations. Touchdown Tavern has endless options, the buffalo chicken flatbread and the brisket sandwich were both surprisingly good.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('6d66f29e65a81ab4547e638d','venue','3784','atmosphere','snapback-official','Snapback','When the whole stadium fills it gets loud, especially next to the band and in the student section. They added club seating sections that give parts of the lower bowl a wine-and-cheese feel.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('09aafb5f6927b2db740f304b','venue','3784','tips','snapback-official','Snapback','If College GameDay is in town for an 11 a.m. kick, the tailgate scene can be subdued because students are already inside and have been partying all week. Pace yourself so you peak for kickoff, not before.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('4a4e560f5e0b1a2af8d7b451','venue','3784','best-seats','snapback-official','Snapback','Students follow the rules here, so a respectful field-storm only happens to celebrate. The Matador song before the game is a highlight.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO reviews (id,scope,target_id,game_id,user_id,author,rating,body,created_at) VALUES ('snapback-review-3784','venue','3784',NULL,'snapback-official','Snapback',7,'The overall weekend experience in Lubbock with Raiderville and the barbecue was amazing and the facilities are the nicest in football. The Saturday game-day crowd for an 11 a.m. GameDay kick was underwhelming because everyone had been up for 48 hours, which dragged the in-stadium score.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('201c41e3d35bf5234647a6d8','venue','3785','atmosphere','snapback-official','Snapback','Inside Jordan-Hare the crowd is rocking and it builds in levels through the game, a veteran crowd that keeps getting louder. The outside tailgate atmosphere, like most SEC, is chill and low-key rather than rowdy.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('7699afd5d901c0fa1f3bde41','venue','3785','food','snapback-official','Snapback','There was a 30-minute line for the Bell soft pretzel. It is good if you are cold and have had a few beers, but the long wait makes it tough to fully recommend.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('8273c5062346d4053e9cc7da','venue','3785','before','snapback-official','Snapback','Toomer''s Corner and the famous oak trees are the iconic spot; fans roll them with toilet paper after a big win, one of the coolest traditions in college sports. The eagle flight before kickoff and dotting the field are elite traditions.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('4657aedae52719b2e59a7935','venue','3785','tips','snapback-official','Snapback','This is the Iron Bowl rivalry with Alabama, rich in history and hatred, though the heat has cooled a touch during Auburn''s down stretch. Auburn campus itself did not blow us away.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO reviews (id,scope,target_id,game_id,user_id,author,rating,body,created_at) VALUES ('snapback-review-3785','venue','3785',NULL,'snapback-official','Snapback',8,'The traditions here are among the best in college football, from the eagle flight to Toomer''s Corner rolling, and inside the stadium it gets genuinely loud. The outside tailgate was a little underwhelming SEC-chill, but the Iron Bowl history and a one-possession finish made it a bucket-list game.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('f95959a3ae52fad60a3aa426','venue','3994','atmosphere','snapback-official','Snapback','The students showed up and did their part and it got genuinely loud, but for this rivalry game with both teams struggling it was not the rowdiest the stadium gets. A sellout crowd, but a bit of a misery-loves-company vibe given the records.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('3c0818d9d0a7ebedfc847166','venue','3994','before','snapback-official','Snapback','Lots of house-divided tailgates with Clemson and Carolina fans mixed together. The hatred is real, this is the Palmetto Bowl and fans say they do not care about the record as long as they beat their rival.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('749752715354233a045e8399','venue','3994','tips','snapback-official','Snapback','The 2001 Space Odyssey entrance is a signature, though it hits harder in a winning season. Sandstorm is a fun every-game tradition. Bring layers, it can be in the low 30s.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('bf23bedb77eb6ab4ae1a224a','venue','3994','best-seats','snapback-official','Snapback','Great campus and at night the bars around Columbia were buzzing.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO reviews (id,scope,target_id,game_id,user_id,author,rating,body,created_at) VALUES ('snapback-review-3994','venue','3994',NULL,'snapback-official','Snapback',5,'Williams-Brice gets credit for a sellout and the students brought it late, but for a year where both rivals were down the energy was just fine and the entrance traditions did not pop. The campus is solid and the night bar scene is good. Not the year to catch this game.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('3cfc733133e34603e8baa6db','venue','3700','atmosphere','snapback-official','Snapback','This is midweek MACtion, a Tuesday-night game in 30-degree cold with rain or snow. Embrace the madness; chaotic plays, multiple fumbles per drive, and a small but devoted shirtless crowd. By the fourth quarter most of the student section has cleared out, and that is fine.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('d2bec4c64a16cb39dd8ba80f','venue','3700','food','snapback-official','Snapback','Smaller schools tend to have the better food, and Bowling Green delivered. The stuffed cheddar-jalapeno item was good and the bucket of donuts was a happy surprise. They even have a local beer, the Juniper ale.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('152db4a6636b45f1705f956c','venue','3700','before','snapback-official','Snapback','Dress for the cold; you exhaust more energy when freezing. People hyped hitting the bars after, but realistically you will just want a warm bed after sitting in the cold all night.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('37b27ecb4d19c26aad94c7ce','venue','3700','tips','snapback-official','Snapback','You can roam anywhere and easily find your group by looking at the big screen during commercial breaks. Pudge the team''s animal mascot is an internet sensation worth seeking out.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO reviews (id,scope,target_id,game_id,user_id,author,rating,body,created_at) VALUES ('snapback-review-3700','venue','3700',NULL,'snapback-official','Snapback',7,'A true sicko game and a wonderful breath of fresh air, college football in its purest form away from the talking heads. Freezing cold Tuesday-night MACtion in the middle of Ohio is gritty, chaotic and genuinely fun. Worth doing at least one game like this a year.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('7d70a547a1311aa3bf21aca2','venue','3835','getting-there','snapback-official','Snapback','Old stadium that can be pretty difficult to navigate at times, so leave yourself extra time to find your way around. The fans pack into Norman in full force for a home playoff game.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('8f5f699b72c07a44bcbf72ba','venue','3835','before','snapback-official','Snapback','Get to campus early to soak in the tailgate scene. They block off the streets near Lloyd''s and O''Connell''s about four hours before kick and the bars, frats and tailgates are all going. Grab official CFP and team merch at the stadium since that is where the official playoff gear is sold, not the bookstore.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('438a0a5909b4c971f0c0a48d','venue','3835','food','snapback-official','Snapback','Get the state fair corn dogs, they were elite. The beef dog with pulled pork, coleslaw, fried onions and a creamy cheese sauce was immaculate, and the Fletcher''s jalapeno corn dog is a Texas state fair classic worth trying.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('82ce11e73272d36c732b89c4','venue','3835','atmosphere','snapback-official','Snapback','The stadium entrance is one of the better ones you will see, with firework flags, fireworks out of the drum line, the Sooner Schooner and the team running out. The building gets juiced and rocking for a big night game, on par with Notre Dame but a bit more man of the people.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('32ed458f5447e61cb0675544','venue','3835','best-seats','snapback-official','Snapback','An old-style bowl where sound funnels and stays loud. Being close to the field gives a great feel, but expect the place to empty out fast if the game gets out of hand.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO reviews (id,scope,target_id,game_id,user_id,author,rating,body,created_at) VALUES ('snapback-review-3835','venue','3835',NULL,'snapback-official','Snapback',8,'A big game in Norman is pound for pound a great college football experience. The stadium was absolutely juiced and rocking with everything a home playoff game should be: the bars, the frats, the entrance, the pregame, the fireworks and elite corn dogs. The old stadium can be tough to navigate, and the atmosphere takes a hit if the home team blows a lead, but the bottom line is a fantastic environment.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('e9611c4bb84a59a90a5c2223','venue','3653','atmosphere','snapback-official','Snapback','The famous blue turf is a real sight to behold and worth seeing in person at least once, even if it is jarring at first. Crowd turnout is modest and there is not much pregame fanfare, but once the game gets going the stands fill in and both fan bases show out better than expected.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('39fcdfe5d71d8f575a267be9','venue','3653','food','snapback-official','Snapback','Do not come expecting potato dishes, the lack of potato-based food items in the stadium is the biggest disappointment. The pizza cone is a gimmick that is messy to eat, you are better off with a normal slice. Outside the stadium, Boise Fry Company is worth a stop for fries with blueberry ketchup and sweet potato fries.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('88c268a843efecab0720e8b3','venue','3653','best-seats','snapback-official','Snapback','The view from up high is beautiful and stunning, and it is a very accessible, easy stadium to get around. North end zone bleachers are being converted to suites, so that area may be quieter going forward.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('44b85c1f4867e40adc35db59','venue','3653','tips','snapback-official','Snapback','It is a good family-friendly bowl with a fun potato mascot (Spudzy) and a little bit for everyone. Two six-and-six teams battling for a seventh win, so set your expectations accordingly, but it is far from the worst bowl game and is genuinely entertaining.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO reviews (id,scope,target_id,game_id,user_id,author,rating,body,created_at) VALUES ('snapback-review-3653','venue','3653',NULL,'snapback-official','Snapback',6,'Not even close to being a punishment. Bowl games are something every big college football fan should attend once, and this one has the fun gimmick of the blue turf, a silly mascot and a good place to bring the whole family. The food was disappointing with no potato products, and it was not sold out, but once the game got going each team''s turnout impressed. Recommended.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('128cb87dafedec661dfbe4fa','venue','2024','atmosphere','snapback-official','Snapback','Built 37 feet underground with a low flat roof and no center-hung scoreboard, so there is nowhere for the sound to go and it bounces straight back down onto the court, making it one of the loudest arenas in college basketball. Even down 10-plus on a comeback run it got louder than some college football games. The Howl Raisers student section stands the entire game and the snake mascot is a fixture.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('23702e282d8a12ce9658e309','venue','2024','getting-there','snapback-official','Snapback','Albuquerque sits at higher elevation than Denver at about 5,326 feet, then you walk down the famous ramp 37 feet below street level into the arena. The mantra here is a mile high and louder.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('d9f907ec702f172b87d2b08e','venue','2024','food','snapback-official','Snapback','Get the Laguna Burger, which started as a gas station restaurant. Green chilies, tomato and melted American cheese on a sesame bun, cooked to order in the back rather than sitting out. The melted cheese and green chili are the secret, green chili is a must-try.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('8e380fa3134203a90e9f0ba4','venue','2024','before','snapback-official','Snapback','Basketball here has no real pregame scene, fans show up for the game, get loud and leave, so do not expect a tailgate. Check out the campus bookstore for solid merch.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('d0cc52b414a89628c2a4cc94','venue','2024','best-seats','snapback-official','Snapback','Any game and every game is loud and matters to these fans, so it is a must-go for any sports fan at least once.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO reviews (id,scope,target_id,game_id,user_id,author,rating,body,created_at) VALUES ('snapback-review-2024','venue','2024',NULL,'snapback-official','Snapback',7,'The most unique stadium I have been to, built 37 feet underground with a roof that traps all the sound and bounces it back onto the court, making any game extremely loud. The crowd brought it even down double digits on a comeback. Green chili on the Laguna Burger is a best-kept secret. The only thing missing was the team completing the comeback, which would have taken the roof off.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('1678d72586de84726e276674','venue','1823','best-seats','snapback-official','Snapback','Snapback sat in VIP seats practically on the floor, close enough to be right on top of the visiting team''s bench. If you can swing courtside, you are within arm''s reach of the players.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('414bbfcaf7c1484da0114471','venue','1823','tips','snapback-official','Snapback','The team store inside the arena had current player jerseys in stock, including the latest City Edition, so you can grab gear during the game.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('4000c84b3cc514d6d1c3d0b2','venue','2559','before','snapback-official','Snapback','Before playoff games the Thunder host Thunder in the Park right by the arena, with live music, food trucks, and ticket giveaways. It is a fun free way to warm up before heading in.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('fe534e2f05386f7d76e4e6bf','venue','2559','atmosphere','snapback-official','Snapback','Loud City lives up to the name. Fans cheer through opposing runs instead of going quiet, and they keep the energy up the whole game. Locals call it the loudest building they have been in.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('a5bab4234f87df840955c6cb','venue','2559','tips','snapback-official','Snapback','Every seat in the building gets a rally shirt placed on it for playoff games, and there is a t-shirt exchange where you can size up to 2XL or 3XL. Wear the shirt, it is part of the deal here.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('5292af0b5cfe33428d4b61f0','venue','2559','food','snapback-official','Snapback','The chicken tinga tacos at the concession stands were genuinely good. Easy, accommodating, low-stress concourse compared to bigger-market arenas.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('785eb35bb651421312f849b8','venue','2559','getting-there','snapback-official','Snapback','Everything around the arena is easy and accommodating, from parking to getting in the door. Far less stressful than fighting crowds and ticket scalpers at bigger-market buildings.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('ff32d5f7a5d7cf8d801faec9','venue','3947','atmosphere','snapback-official','Snapback','After a monsoon rain stopped, it was basically a sellout and loud the entire game. Our section next to the student section was the only one standing the whole game. Everyone who had a ticket showed up despite the weather.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('be03ad6324c94531724bce58','venue','3947','food','snapback-official','Snapback','One of the best regular stadium-food scores we have given with no special access. The honey chicken tenders and the birria taco specialty item were both excellent, and the cheeseburger hit the spot too.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('971498e53fc890f1cf2a63bf','venue','3947','before','snapback-official','Snapback','Tempe is extremely nice and feels more like a college city than a college town. Old Town Scottsdale is one of the best going-out scenes in the country, and Phoenix is about 20 minutes away.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('189c5b951002e88a8ee30085','venue','3947','tips','snapback-official','Snapback','The stadium is built into the desert backdrop and looks great. Beware the rare monsoon rain, locals say it happens about five times a year but when it hits it really hits.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('4d0a42003a3ca6ecaed6ec79','venue','3947','best-seats','snapback-official','Snapback','Sit near the student section for the loudest, most consistent standing energy in the building.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO reviews (id,scope,target_id,game_id,user_id,author,rating,body,created_at) VALUES ('snapback-review-3947','venue','3947',NULL,'snapback-official','Snapback',7,'A great experience just outside the top tier. The stadium is a little old but the gameplay, the surprisingly elite concession food, and the Tempe and Scottsdale scene make it well worth a stop if you are on the West Coast. You can build a whole sports trip around it.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('2c70065e262ac1c618c99326','venue','3970','atmosphere','snapback-official','Snapback','For this Fiesta Bowl playoff game the crowd was roughly 92 percent one fan base, so it played like a near home game with the other side barely showing buzz. Great anthem and big game feel, though being up in a suite can dampen the energy a bit.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('f5c6011fc8598ce2328dfa1e','venue','3970','best-seats','snapback-official','Snapback','We watched from one of the biggest suites you will ever be in, which is comfortable but removes you from the crowd noise. The retractable design with real grass rolled in is a highlight you can literally smell.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('1533e1ea5940d0f605134800','venue','3970','getting-there','snapback-official','Snapback','The stadium uses smart two-way traffic flow for foot traffic in and out, which moves the crowd efficiently. Keep to your lane and you fly through.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('58b8868b2c3ad7695c9a73df','venue','3970','tips','snapback-official','Snapback','They bring the natural grass field in and snow it, and you can smell it. A genuinely cool stadium feature for a neutral-site playoff game.','2026-07-12T21:14:43.099Z');
INSERT OR REPLACE INTO reviews (id,scope,target_id,game_id,user_id,author,rating,body,created_at) VALUES ('snapback-review-3970','venue','3970',NULL,'snapback-official','Snapback',7,'A neutral-site College Football Playoff game that delivered with a tremendous Cinderella matchup. The retractable-roof stadium with real grass rolled in is a unique touch, and the two-way traffic flow makes getting in and out easy. The crowd skewed heavily to one fan base which gave it an almost home feel, and watching from a massive suite was comfortable even if it took some energy off the atmosphere.','2026-07-12T21:14:43.099Z');
COMMIT;
